24	// Client pulls OCI artifacts from a registry entirely in memory.
25	type Client struct {
26		host      string // registry hostname[:port], no scheme
27		user      string
28		password  string
29		plainHTTP bool
30		insecure  bool // skip TLS certificate verification
31	}
32	
33	// Option configures a Client.
34	type Option func(*Client)
35	
36	// Insecure disables TLS certificate verification.
37	// Useful for Harbor instances with self-signed certificates.
38	func Insecure() Option {
39		return func(c *Client) { c.insecure = true }
40	}
41	
42	// NewClient creates a Client from a db.Repository.
43	// The password stored in repo is RSA-encrypted and will be decrypted automatically.
44	func NewClient(repo *db.Repository, opts ...Option) (*Client, error) {
45		password, err := util.DecryptWithPrivateKey(repo.Password)
46		if err != nil {
47			return nil, fmt.Errorf("decrypt repository password: %w", err)
48		}
49		c := buildClient(repo.Address, repo.User, password)
50		for _, o := range opts {
51			o(c)
52		}
53		return c, nil
54	}
55	
56	// NewClientPlain creates a Client with a plain-text password.
57	// Intended for local testing; do not use in production.
58	func NewClientPlain(address, user, password string, opts ...Option) *Client {
59		c := buildClient(address, user, password)
60		for _, o := range opts {
61			o(c)
62		}
63		return c
64	}
65	
66	func buildClient(address, user, password string) *Client {
67		plainHTTP := strings.HasPrefix(address, "http://")
68		host := strings.TrimPrefix(address, "https://")
69		host = strings.TrimPrefix(host, "http://")
70		host = strings.TrimRight(host, "/")
71		return &Client{
72			host:      host,
73			user:      user,
74			password:  password,
75			plainHTTP: plainHTTP,
76		}
77	}
78	
79	// PullFile fetches an OCI artifact from the registry and returns the raw bytes
80	// of the file named filename.
81	//
82	// Two strategies are attempted for each layer, in order:
83	//  1. Direct match: the layer carries an org.opencontainers.image.title annotation
84	//     that equals filename (plain OCI artifacts).
85	//  2. Archive search: the layer is decompressed as gzip+tar and every entry
86	//     whose base name equals filename is returned (Helm charts pushed as a
87	//     single .tgz layer).
88	//
89	// reference is the image path + tag or digest relative to the registry host,
90	// e.g. "myproject/mychart:1.2.3" or "myproject/mychart@sha256:<hex>".
91	func (c *Client) PullFile(ctx context.Context, reference, filename string, maxSize int) ([]byte, error) {
92		repoPath, ref, err := splitReference(reference)
93		if err != nil {
94			return nil, err
95		}
96	
97		repo, err := remote.NewRepository(c.host + "/" + repoPath)
98		if err != nil {
99			return nil, fmt.Errorf("create remote repository %q: %w", c.host+"/"+repoPath, err)
100		}
101		repo.PlainHTTP = c.plainHTTP
102		repo.Client = &auth.Client{
103			Client: c.httpClient(),
104			Cache:  auth.DefaultCache,
105			Credential: auth.StaticCredential(c.host, auth.Credential{
106				Username: c.user,
107				Password: c.password,
108			}),
109		}
110	
111		_, manifestRC, err := repo.FetchReference(ctx, ref)
112		if err != nil {
113			return nil, fmt.Errorf("fetch manifest %s@%s: %w", repoPath, ref, err)
114		}
115		defer manifestRC.Close()
116	
117		manifestBytes, err := io.ReadAll(manifestRC)
118		if err != nil {
119			return nil, fmt.Errorf("read manifest: %w", err)
120		}
121	
122		var manifest ocispec.Manifest
123		if err := json.Unmarshal(manifestBytes, &manifest); err != nil {
124			return nil, fmt.Errorf("parse manifest: %w", err)
125		}
126	
127		for i, layer := range manifest.Layers {
128			rc, err := repo.Blobs().Fetch(ctx, layer)
129			if err != nil {
130				return nil, fmt.Errorf("fetch layer[%d] (digest %s): %w", i, layer.Digest, err)
131			}
132	
133			data, found, extractErr := extractFile(rc, filename, maxSize)
134			rc.Close()
135	
136			if extractErr != nil {
137				return nil, fmt.Errorf("extract from layer[%d]: %w", i, extractErr)
138			}
139			if found {
140				return data, nil
141			}
142		}
143	
144		return nil, fmt.Errorf("file %q not found in artifact %q (%d layers)", filename, reference, len(manifest.Layers))
145	}
146	
147	// extractFile reads blobRC and returns the content of filename.
148	//
149	// Returns (data, true, nil) on success, (nil, false, nil) when the file is
150	// simply not present in this blob, or (nil, false, err) on a real I/O error.
151	func extractFile(blobRC io.Reader, filename string, maxSize int) ([]byte, bool, error) {
152		gr, err := gzip.NewReader(blobRC)
153		if err != nil {
154			// Not a gzip stream; skip this layer.
155			return nil, false, nil
156		}
157		defer gr.Close()
158	
159		tr := tar.NewReader(gr)
160		for {
161			hdr, err := tr.Next()
162			if err == io.EOF {
163				break
164			}
165			if err != nil {
166				return nil, false, fmt.Errorf("read tar entry: %w", err)
167			}
168			if hdr.Typeflag != tar.TypeReg {
169				continue
170			}
171			if filepath.Base(hdr.Name) == filename {
172				if hdr.Size > int64(maxSize) {
173					return nil, false, fmt.Errorf("file %q too large (%d bytes, max %d)", filename, hdr.Size, maxSize)
174				}
175				data, err := io.ReadAll(tr)
176				if err != nil {
177					return nil, false, fmt.Errorf("read tar entry %q: %w", hdr.Name, err)
178				}
179				return data, true, nil
180			}
181		}
182	
183		return nil, false, nil
184	}
185	
186	// splitReference splits a reference such as "project/chart:1.0.0" into the
187	// repository path ("project/chart") and the tag or digest ("1.0.0").
188	// Digest references of the form "project/chart@sha256:<hex>" are also handled.
189	func splitReference(reference string) (repoPath, ref string, err error) {
190		if idx := strings.Index(reference, "@"); idx >= 0 {
191			return reference[:idx], reference[idx+1:], nil
192		}
193		lastSlash := strings.LastIndex(reference, "/")
194		rest := reference[lastSlash+1:]
195		if idx := strings.LastIndex(rest, ":"); idx >= 0 {
196			tagIdx := lastSlash + 1 + idx
197			return reference[:tagIdx], reference[tagIdx+1:], nil
198		}
199		return "", "", fmt.Errorf("reference %q must include a tag (:tag) or digest (@sha256:...)", reference)
200	}
201	
202	// httpClient returns an HTTP client configured according to the Client options.
203	func (c *Client) httpClient() *http.Client {
204		if !c.insecure {
205			return retry.DefaultClient
206		}
207		return &http.Client{
208			Transport: retry.NewTransport(&http.Transport{
209				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
210			}),
211		}
212	}
