42	func (r *Repository) Gets(db *gorm.DB, size, current int) ([]Repository, int64, error) {
43	
44		db = db.Where("is_deleted =0")
45	
46		if r.Name != "" {
47			db = db.Where("name LIKE ?", "%"+r.Name+"%")
48		}
49	
50		rps := make([]Repository, 0)
51		db = db.Model(&Repository{})
52		var total int64
53		err := db.Count(&total).Error
54		if err != nil {
55			return nil, 0, err
56		}
57		if size != 0 && current != 0 {
58			db = WrapLimitOffset(db, size, current)
59		}
60		err = db.Find(&rps).Error
61		if err != nil {
62			return nil, 0, err
63		}
