102	// 获取指定字段
103	
104	func withOrder(field string, desc bool) func(db *gorm.DB) *gorm.DB {
105		return func(db *gorm.DB) *gorm.DB {
106			allowedFields := map[string]bool{
107				"id":              true,
108				"name":            true,
109				"address":         true,
110				"domain":          true,
111				"create_author":   true,
112				"description":     true,
113				"p2p_instance_id": true,
114				"created_at":      true,
115				"updated_at":      true,
116			}
117	
118			if !allowedFields[field] {
119				return db
120			}
121	
122			if desc {
123				return db.Order(field + " DESC")
124			}
125			return db.Order(field)
126		}
127	}
