92		suiteInCluster, err := c.getAISuiteInCluster(clusterCode, name, chartVersion, namespace)
93		if err != nil {
94			log.Errorf("encountered error while getting AI Suite in cluster: %v", err)
95			if namespace != "" {
96				return nil, fmt.Errorf("encountered error while getting AI Suite in cluster: %w", err)
97			}
98		}
99	
100		suiteInRegistry := new(aisuite.GetAISuiteResp)
101		suiteRegistry, err := getSuiteRegistry(c.db)
102		if err != nil {
103			log.Errorf("failed to get suite registry: %v", err)
104		} else {
105			suiteInRegistry, err = getAISuiteInRegistry(ctx, suiteRegistry, name, chartVersion)
106			if err != nil {
107				log.Errorf("encountered error while getting AI Suite in registry: %v", err)
108				suiteInRegistry = nil
109			}
110		}
111	
112		switch {
113		case suiteInCluster == nil && suiteInRegistry == nil:
114			return nil, fmt.Errorf("AI Suite %s not found in both cluster and registry", name)
115		case suiteInCluster != nil && suiteInRegistry == nil:
116			return suiteInCluster, nil
117		case suiteInCluster == nil && suiteInRegistry != nil:
