196	func (c *Controller) installAISuiteInCluster(clusterCode, name, chartVersion string, customValues []*aisuite.CustomValues) error {
197		suiteRegistry, err := getSuiteRegistry(c.db)
198		if err != nil {
199			log.Errorf("failed to get suite registry: %v", err)
200			return fmt.Errorf("failed to get suite registry: %w", err)
201		}
202		registryHost := strings.TrimPrefix(suiteRegistry.Address, "https://")
203		registryHost = strings.TrimPrefix(registryHost, "http://")
204		repoChart := fmt.Sprintf("oci://%s/%s/%s", registryHost, suiteChartProject, name)
205		setValues := make(map[string]interface{})
206		req := &helm.InstallOrUpgradeReleaseRequest{
207			HelmRepository: helm.HelmRepository{
208				Host:     registryHost,
209				UserName: suiteRegistry.User,
210				Password: suiteRegistry.Password,
211			},
212			CreateNamespace: true,
213			Name:            name,
214			Wait:            wait,
215			Timeout:         waitTimeout,
216			RepoChart:       repoChart,
217			Version:         chartVersion,
218			Labels:          map[string]string{"DeployedBy": "TAPAISuite"},
219		}
220		for _, cv := range customValues {
221			switch cv.Name {
222			case helmParamPrefix + "namespace":
223				namespace, ok := cv.Value.(string)
224				if !ok {
225					return fmt.Errorf("invalid type for namespace value: expected string, got %T", cv.Value)
226				}
227				req.Namespace = namespace
228			case helmParamPrefix + "timeout":
229				waitTimeoutFloat, ok := cv.Value.(float64) // JSON numbers are unmarshaled into float64
230				if !ok {
231					return fmt.Errorf("invalid type for timeout value: expected int, got %T", cv.Value)
232				}
233				waitTimeout := util.ToInt(waitTimeoutFloat)
234				req.Timeout = time.Duration(waitTimeout) * time.Second
235			default:
236				expandDotKey(setValues, cv.Name, cv.Value)
237			}
238		}
239		if req.Namespace == "" {
240			return fmt.Errorf("namespace is required for installing AI Suite in cluster")
241		}
242	
243		req.Values = setValues
244		return c.apiserverGetter.InstallRelease(clusterCode, req)
245	}
