370	// 用oras拉取chart，解压后读取其中的tap_aisuite_values.json, 作为套件的定制化参数schema
371	func getCustomValueSchema(ctx context.Context, suiteRegistry *db.Repository, name, digest string) (json.RawMessage, error) {
372		if suiteRegistry == nil {
373			return nil, fmt.Errorf("suite registry is nil")
374		}
375		if name == "" {
376			return nil, fmt.Errorf("suite name is empty")
377		}
378		if digest == "" {
379			return nil, fmt.Errorf("digest is empty")
380		}
381	
382		orasClient, err := oras.NewClient(suiteRegistry, oras.Insecure())
383		if err != nil {
384			log.Errorf("failed to create oras client: %v", err)
385			return nil, fmt.Errorf("failed to create oras client: %w", err)
386		}
387	
388		artifactRef := fmt.Sprintf("%s/%s@%s", suiteChartProject, name, digest)
389		schemaBytes, err := orasClient.PullFile(ctx, artifactRef, jsonSchemaFileName, maxSchemaSize)
390		if err != nil {
391			log.Errorf("failed to pull custom value schema from artifact %s: %v", artifactRef, err)
392			return nil, fmt.Errorf("failed to pull custom value schema from artifact %s: %w", artifactRef, err)
393		}
394		if json.Valid(schemaBytes) {
395			return json.RawMessage(schemaBytes), nil
396		} else {
397			log.Errorf("custom value schema pulled from artifact %s is not valid JSON", artifactRef)
398			return nil, fmt.Errorf("custom value schema pulled from artifact %s is not valid JSON", artifactRef)
399		}
400	}
