456		if suiteRegistry == nil {
457			return nil, fmt.Errorf("suite registry is nil")
458		}
459	
460		registryOpts := harbor.DefaultOptions().WithPageSize(100).WithPage(1)
461		registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
462		if err != nil {
463			log.Errorf("failed to get registry client: %v", err)
464			return nil, err
465		}
466	
467		reposInSuiteRegistry := make([]*model.Repository, 0)
468		for {
469			repos, err := registryCli.GetClient().ListRepositories(ctx, suiteChartProject)
470			if err != nil {
471				log.Errorf("failed to list repositories in suite registry: %v", err)
472				return nil, err
473			}
474			reposInSuiteRegistry = append(reposInSuiteRegistry, repos...)
475			if int64(len(repos)) < registryOpts.PageSize {
